import sailpoint.object.Identity;
  import sailpoint.object.Filter;
  import sailpoint.tools.Util;

  Map returnMap = new HashMap();
  if (account != null && Util.isNotNullOrEmpty(account.getAttribute("User Name"))) {
    String userid = account.getAttribute("User Name");
    String[] splitUserId = userid.split("\\\\");
    String samAccountName = null;
    if(splitUserId.length > 1) {
      samAccountName = splitUserId[1];
    }
    if (Util.isNotNullOrEmpty(samAccountName )) {
      Filter samAccountNameFilter = Filter.eq("samAccountName", samAccountName);
      Identity identity = context.getUniqueObject(Identity.class, samAccountNameFilter);
      if (identity != null) {
        returnMap.put("identityName", identity.getName());
      }
    }
  }
  return returnMap;
